import { useEffect, useState } from "react";
import { bookService } from "../services/api";
import MessageBanner from "../components/MessageBanner";
import { isAdmin } from "../utils/auth";

const initialForm = {
  title: "",
  author: "",
  ISBN: "",
  quantity: ""
};

const BooksPage = () => {
  const adminView = isAdmin();
  const [books, setBooks] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [editingBookId, setEditingBookId] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const loadBooks = async () => {
    try {
      setError("");
      const res = await bookService.getAll();
      setBooks(res.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to fetch books");
    }
  };

  useEffect(() => {
    loadBooks();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setError("");
      setMessage("");
      if (editingBookId) {
        await bookService.update(editingBookId, {
          ...form,
          quantity: Number(form.quantity)
        });
        setMessage("Book updated successfully");
      } else {
        await bookService.create({
          ...form,
          quantity: Number(form.quantity)
        });
        setMessage("Book added successfully");
      }
      setForm(initialForm);
      setEditingBookId("");
      await loadBooks();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to save book");
    }
  };

  const handleDelete = async (id) => {
    try {
      setError("");
      setMessage("");
      await bookService.remove(id);
      setMessage("Book deleted successfully");
      await loadBooks();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to delete book");
    }
  };

  const handleEdit = (book) => {
    setEditingBookId(book._id);
    setForm({
      title: book.title,
      author: book.author,
      ISBN: book.ISBN,
      quantity: String(book.quantity)
    });
  };

  return (
    <div>
      <h2 className="text-2xl font-semibold mb-6">Books</h2>
      <MessageBanner message={message} />
      <MessageBanner message={error} variant="error" />

      {adminView && (
        <form onSubmit={handleSubmit} className="bg-white shadow rounded-lg p-4 mb-6">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
            <input
              className="border rounded px-3 py-2"
              name="title"
              placeholder="Title"
              value={form.title}
              onChange={handleChange}
              required
            />
            <input
              className="border rounded px-3 py-2"
              name="author"
              placeholder="Author"
              value={form.author}
              onChange={handleChange}
              required
            />
            <input
              className="border rounded px-3 py-2"
              name="ISBN"
              placeholder="ISBN"
              value={form.ISBN}
              onChange={handleChange}
              required
            />
            <input
              className="border rounded px-3 py-2"
              name="quantity"
              type="number"
              min="0"
              placeholder="Quantity"
              value={form.quantity}
              onChange={handleChange}
              required
            />
          </div>
          <div className="mt-4 flex gap-2">
            <button
              type="submit"
              className="bg-slate-800 text-white px-4 py-2 rounded hover:bg-slate-700"
            >
              {editingBookId ? "Update Book" : "Add Book"}
            </button>
            {editingBookId && (
              <button
                type="button"
                className="bg-slate-200 text-slate-800 px-4 py-2 rounded hover:bg-slate-300"
                onClick={() => {
                  setEditingBookId("");
                  setForm(initialForm);
                }}
              >
                Cancel
              </button>
            )}
          </div>
        </form>
      )}

      <div className="bg-white shadow rounded-lg overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-100">
            <tr>
              <th className="p-3">Title</th>
              <th className="p-3">Author</th>
              <th className="p-3">ISBN</th>
              <th className="p-3">Quantity</th>
              <th className="p-3">Available</th>
              {adminView && <th className="p-3">Action</th>}
            </tr>
          </thead>
          <tbody>
            {books.map((book) => (
              <tr key={book._id} className="border-t">
                <td className="p-3">{book.title}</td>
                <td className="p-3">{book.author}</td>
                <td className="p-3">{book.ISBN}</td>
                <td className="p-3">{book.quantity}</td>
                <td className="p-3">{book.availableCopies}</td>
                {adminView && (
                  <td className="p-3 space-x-2">
                    <button
                      type="button"
                      className="bg-amber-600 text-white px-3 py-1 rounded hover:bg-amber-500"
                      onClick={() => handleEdit(book)}
                    >
                      Edit
                    </button>
                    <button
                      type="button"
                      className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-500"
                      onClick={() => handleDelete(book._id)}
                    >
                      Delete
                    </button>
                  </td>
                )}
              </tr>
            ))}
            {!books.length && (
              <tr>
                <td className="p-3 text-gray-500" colSpan={adminView ? 6 : 5}>
                  No books available.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default BooksPage;
